gz_(){return"Art Elevate \u0647\u0648 \u062a\u0637\u0628\u064a\u0642 \u0645\u0628\u062a\u0643\u0631 \u0645\u0635\u0645\u0645 \u0644\u0639\u0634\u0627\u0642 \u0627\u0644\u0641\u0646 \u0648\u0627\u0644\u0645\u0628\u062f\u0639\u064a\u0646 \u0639\u0644\u0649 \u062d\u062f \u0633\u0648\u0627\u0621. \u062a\u0645 \u0625\u0646\u0634\u0627\u0624\u0647 \u0628\u0648\u0627\u0633\u0637\u0629 Vaishnav\u060c \u0648\u064a\u0631\u0628\u0637 \u0627\u0644\u0641\u0646\u0627\u0646\u064a\u0646 \u0628\u0627\u0644\u0645\u0634\u062a\u0631\u064a\u0646 \u0645\u0646 \u062e\u0644\u0627\u0644 \u0645\u0646\u0635\u0629 \u0633\u0647\u0644\u0629 \u0627\u0644\u0627\u0633\u062a\u062e\u062f\u0627\u0645. \u064a\u0645\u0643\u0646 \u0644\u0644\u0641\u0646\u0627\u0646\u064a\u0646 \u062a\u062d\u0645\u064a\u0644 \u0623\u0639\u0645\u0627\u0644\u0647\u0645 \u0648\u062a\u062d\u062f\u064a\u062f \u0627\u0644\u0623\u0633\u0639\u0627\u0631 \u0648\u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u062c\u0645\u0647\u0648\u0631 \u0639\u0627\u0644\u0645\u064a. \u064a\u0645\u0643\u0646 \u0644\u0644\u0645\u0634\u062a\u0631\u064a\u0646 \u0627\u0633\u062a\u0643\u0634\u0627\u0641 \u0645\u062c\u0645\u0648\u0639\u0629 \u0648\u0627\u0633\u0639\u0629 \u0645\u0646 \u0623\u0646\u0645\u0627\u0637 \u0648\u0641\u0626\u0627\u062a \u0627\u0644\u0641\u0646. \u064a\u0636\u0645\u0646 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0627\u0644\u0645\u0639\u0627\u0645\u0644\u0627\u062a \u0627\u0644\u0622\u0645\u0646\u0629 \u0648\u062a\u062c\u0631\u0628\u0629 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0627\u0644\u0633\u0644\u0633\u0629. \u0643\u0645\u0627 \u064a\u062d\u062a\u0648\u064a \u0639\u0644\u0649 \u0645\u062c\u062a\u0645\u0639 \u062d\u064a\u062b \u064a\u0645\u0643\u0646 \u0644\u0644\u0645\u0633\u062a\u062e\u062f\u0645\u064a\u0646 \u0627\u0644\u062a\u0641\u0627\u0639\u0644 \u0648\u0645\u0634\u0627\u0631\u0643\u0629 \u0634\u063a\u0641\u0647\u0645 \u0627\u0644\u0641\u0646\u064a. \u064a\u062f\u0639\u0645 Art Elevate \u0627\u0644\u0641\u0646\u0627\u0646\u064a\u0646 \u0645\u0646 \u062e\u0644\u0641\u064a\u0627\u062a \u0645\u062a\u0646\u0648\u0639\u0629 \u0648\u064a\u0633\u0627\u0639\u062f\u0647\u0645 \u0639\u0644\u0649 \u0627\u0643\u062a\u0633\u0627\u0628 \u0627\u0644\u0638\u0647\u0648\u0631. \u0633\u0648\u0627\u0621 \u0643\u0646\u062a \u062a\u0634\u062a\u0631\u064a \u0623\u0648 \u062a\u0628\u064a\u0639\u060c \u0641\u0625\u0646 Art Elevate \u0647\u0648 \u0628\u0648\u0627\u0628\u062a\u0643 \u0625\u0644\u0649 \u0639\u0627\u0644\u0645 \u0627\u0644\u0641\u0646."},
